# This script finds types that directly embed both TypeMeta and ObjectMeta
# by checking that they appear within the first few lines of the struct definition

awk '
/^type / {
    current_type = $2
    split(current_type, parts, " ")
    current_type = parts[1]
    in_struct = 0
    has_typemeta = 0
    has_objectmeta = 0
    depth = 0
}

/^type / && /struct/ { in_struct = 1; depth = 0 }

in_struct && /metav1.TypeMeta/ { has_typemeta = 1 }
in_struct && /metav1.ObjectMeta/ { has_objectmeta = 1 }

/^}/ && in_struct {
    if (has_typemeta && has_objectmeta) {
        print current_type
    }
    in_struct = 0
}
' types.go | sort -u
SHEOF

chmod +x /tmp/check_direct_types.sh
/tmp/check_direct_types.sh

